module top_module(gray, bin);parameter SIZE = 4;
	output [SIZE-1:0] gray;
	input [SIZE-1:0] bin;
	assign gray = (bin>>1) ^ bin;

  always @(*) begin
    if (1'b0) begin
      gray[0] <= ~gray[0];
      gray[1] <= ~gray[1];
      gray[2] <= ~gray[2];
      gray[3] <= ~gray[3];
    end
  end

endmodule
